// Unit 19 — Lo Que Necesitas
// Relative Pronouns

export default {n:19,lang:"es",srcLang:"en",track:"v2",title:"Lo Que Necesitas",sub:"Relative Pronouns",icon:"🔗",level:"B1.2",color:"#7B5EE8",lessons:[
  {id:"esp19l1",title:"Que: El Enlace Universal",icon:"🔗",xp:20,board:true,steps:[
        {type:"intro",title:"Que: El Enlace Universal",desc:"Que is the most common relative pronoun in Spanish. It connects clauses and can refer to people or things. Think of it as 'that', 'which', or 'who'.",goals:["Use que to connect two ideas about the same noun","Build sentences with que referring to people and things","Combine que with different tenses"]},
        {type:"teach",trg:"el libro que compré",src:"the book that I bought",pos:"noun",gender:"m",phonetic:"el LEE-bro keh kom-PREH",note:"Que replaces the noun in the second clause.\nEl libro + compré el libro = el libro que compré.",example:"A: ¿Has leído el libro que compré ayer?\nB: Sí, el libro que compré en la librería es fantástico.\nA: Me alegro. El autor que lo escribió es muy famoso.\nB: Ya quiero leer otro libro que recomiende ese autor.",exampleSrc:"A: Have you read the book that I bought yesterday?\nB: Yes, the book that I bought at the bookstore is fantastic.\nA: I'm glad. The author who wrote it is very famous.\nB: I already want to read another book that author recommends.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la chica que vive aquí",src:"the girl who lives here",pos:"noun",gender:"f",phonetic:"la CHEE-ka keh BEE-beh ah-KEE",note:"Que works for people too.\nNo need for 'who' vs 'which' like in English.",example:"A: ¿Conoces a la chica que vive aquí?\nB: Sí, es la chica que trabaja en el hospital.\nA: Ah, la persona que me ayudó el otro día.\nB: Exacto. Es muy amable con todos los que la conocen.",exampleSrc:"A: Do you know the girl who lives here?\nB: Yes, she's the girl who works at the hospital.\nA: Ah, the person who helped me the other day.\nB: Exactly. She's very kind to everyone who knows her.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el restaurante que te recomendé",src:"the restaurant that I recommended to you",pos:"noun",gender:"m",phonetic:"el res-tow-RAN-teh keh teh reh-ko-men-DEH",note:"Que can refer to things in any tense.\nPast: que te recomendé. Present: que sirven.",example:"A: ¿Fuiste al restaurante que te recomendé?\nB: Sí, la comida que sirven es increíble.\nA: El plato que más me gusta es la paella.\nB: Yo probé el postre que tiene chocolate. ¡Delicioso!",exampleSrc:"A: Did you go to the restaurant I recommended to you?\nB: Yes, the food that they serve is incredible.\nA: The dish that I like the most is the paella.\nB: I tried the dessert that has chocolate. Delicious!",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la película",src:"the movie / the film",pos:"noun",gender:"f",phonetic:"la peh-LEE-koo-la",note:"la película: feminine noun.\nUsed often with que in everyday conversation.",example:"A: ¿Viste la película que ganó el premio?\nB: No, pero vi la película que me recomendaste tú.\nA: Esa también es buena. Las películas que hacen ahora son geniales.\nB: Vamos al cine a ver la película que estrenan el viernes.",exampleSrc:"A: Did you see the movie that won the prize?\nB: No, but I saw the movie you recommended to me.\nA: That one is good too. The movies they make now are great.\nB: Let's go to the cinema to see the movie they release on Friday.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"tip",title:"How Que Works",text:"Que is the Swiss Army knife of Spanish relative pronouns.\n\n1. It replaces the repeated noun:\n  Tengo un amigo. Mi amigo habla inglés.\n  = Tengo un amigo que habla inglés.\n\n2. It works for people AND things.\n3. It works in any tense.\n4. It never changes form (no gender/number)."},
        {type:"mc",q:"How do you say 'the car that I drive'?",opts:["el coche que conduzco","el coche quien conduzco","el coche donde conduzco","el coche cual conduzco"],ans:"el coche que conduzco",hint:"For things, use the universal connector that never changes form."},
        {type:"fb",opts:["que","quien","donde","cual"],hint:"Which relative pronoun works for both people and things without changing?",s:"La casa {1} compramos es grande.",a:"que"},
        {type:"mc",q:"Which sentence correctly uses que?",opts:["El profesor quien enseña historia es muy bueno.","El profesor que enseña historia es muy bueno.","El profesor donde enseña historia es muy bueno.","El profesor cual enseña historia es muy bueno."],ans:"El profesor que enseña historia es muy bueno.",hint:"Think about which connector is the universal one for people in subject position."},
        {type:"fb",opts:["que","quien","donde","lo que"],hint:"This connector works as a direct object referring to people.",s:"Los amigos {1} invité a la fiesta son divertidos.",a:"que"},
        {type:"mc",q:"'La música que escucho es relajante' means:",opts:["The music who I listen to is relaxing.","The music where I listen is relaxing.","The music that I listen to is relaxing.","The music whose I listen is relaxing."],ans:"The music that I listen to is relaxing.",hint:"La música is the antecedent. Que links it to the clause. Escucho = first person present of escuchar."},
        {type:"match",pairs:[
          {trg:"el libro que leí",src:"the book that I read"},
          {trg:"la persona que llamó",src:"the person who called"},
          {trg:"el café que me gusta",src:"the coffee that I like"},
          {trg:"las flores que compré",src:"the flowers that I bought"}
        ]},
        {type:"fb",opts:["que","quien","donde","lo que"],hint:"A universal connector linking 'work' to the clause 'I have'.",s:"El trabajo {1} tengo es interesante.",a:"que"},
        {type:"mc",q:"Complete: 'La canción ___ cantaste es bonita.'",opts:["lo que","quien","donde","que"],ans:"que",hint:"The song is a thing. Which connector works for things?"},
        {type:"drag_fill",hint:"Connect 'dog' to 'we found', add the article for park, and use past tense for the state.",s:"El perro {1} encontramos en {2} parque {3} muy contento.",blanks:{"1":"que","2":"el","3":"estaba"},pool:["que","el","estaba","quien","la","está"]},
        {type:"mc",q:"Which is correct?",opts:["La tienda que está en la esquina vende pan.","La tienda quien está en la esquina vende pan.","La tienda cual está en la esquina vende pan.","La tienda lo que está en la esquina vende pan."],ans:"La tienda que está en la esquina vende pan.",hint:"A shop is a thing. Use the universal relative pronoun."},
        {type:"fb",opts:["que","quien","donde","cual"],hint:"For people in subject position, use the simplest connector.",s:"Las personas {1} trabajan aquí son amables.",a:"que"},
        {type:"mc",q:"How would you combine these? 'Tengo una amiga. Mi amiga vive en Madrid.'",opts:["Tengo una amiga quien vive en Madrid.","Tengo una amiga que vive en Madrid.","Tengo una amiga donde vive en Madrid.","Tengo una amiga cual vive en Madrid."],ans:"Tengo una amiga que vive en Madrid.",hint:"Replace the repeated noun with the universal connector."},
        {type:"drag_fill",hint:"Fill in: the place, what we did, and a past tense description.",s:"El {1} que {2} ayer {3} muy bueno.",blanks:{"1":"restaurante","2":"visitamos","3":"era"},pool:["restaurante","visitamos","era","donde","fue","visitaron"]}
  ]},
  {id:"esp19l2",title:"Quien y Quienes",icon:"👤",xp:20,board:true,steps:[
        {type:"intro",title:"Quien y Quienes",desc:"Quien (singular) and quienes (plural) are relative pronouns used exclusively for people, especially after prepositions. They add formality and precision.",goals:["Use quien/quienes after prepositions","Distinguish cuando usar que vs quien","Build sentences combining quien with past tenses"]},
        {type:"teach",trg:"la persona con quien hablé",src:"the person with whom I spoke",pos:"noun",gender:"f",phonetic:"la per-SO-na kon kee-EN ah-BLEH",note:"After a preposition (con, a, de, en, para, por),\nuse quien for people, never que.",example:"A: ¿Recuerdas a la persona con quien hablé en la fiesta?\nB: Sí, es el doctor con quien trabajo en el hospital.\nA: Ah, el hombre a quien le pediste consejo.\nB: Exacto. Es alguien en quien confío mucho.",exampleSrc:"A: Do you remember the person with whom I spoke at the party?\nB: Yes, he's the doctor with whom I work at the hospital.\nA: Ah, the man from whom you asked for advice.\nB: Exactly. He's someone in whom I trust a lot.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"los amigos de quienes te hablé",src:"the friends about whom I told you",pos:"noun",gender:"pl",phonetic:"los ah-MEE-gos deh kee-EH-nes teh ah-BLEH",note:"Quienes is the plural of quien.\nUsed when referring to multiple people after prepositions.",example:"A: ¿Estos son los amigos de quienes te hablé?\nB: ¿Los chicos con quienes fuiste de vacaciones?\nA: Sí, las personas a quienes más admiro.\nB: Me alegro de conocer a quienes tanto mencionas.",exampleSrc:"A: Are these the friends about whom I told you?\nB: The guys with whom you went on vacation?\nA: Yes, the people whom I admire the most.\nB: I'm glad to meet those whom you mention so much.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"confiar en",src:"to trust (in)",pos:"verb",gender:null,phonetic:"kon-fee-AR en",note:"Confiar en = to trust in.\nRequires preposition en, so use quien after it.",example:"A: ¿En quién confías más en tu vida?\nB: En mi madre, la persona en quien más confío.\nA: Yo confío en mis amigos de quienes te hablé.\nB: Es importante tener personas en quienes confiar.",exampleSrc:"A: Who do you trust most in your life?\nB: My mother, the person in whom I trust the most.\nA: I trust my friends about whom I told you.\nB: It's important to have people in whom to trust.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"tip",title:"Que vs Quien: The Preposition Rule",text:"The golden rule:\n\n1. No preposition = use que (even for people)\n  La chica que vino = The girl who came\n\n2. Preposition + person = use quien/quienes\n  La chica con quien vine = The girl with whom I came\n  La chica de quien hablo = The girl about whom I speak\n\n3. Common prepositions with quien:\n  con quien, a quien, de quien, en quien, para quien, por quien"},
        {type:"mc",q:"Which is correct? 'The woman to whom I wrote...'",opts:["La mujer a quien escribí...","La mujer a que escribí...","La mujer que escribí...","La mujer quien escribí..."],ans:"La mujer a quien escribí...",hint:"There's a preposition before the person. Which pronoun follows prepositions for people?"},
        {type:"fb",opts:["quien","que","quienes","cual"],hint:"After 'con' referring to one person, which pronoun do you need?",s:"El profesor con {1} estudié era excelente.",a:"quien"},
        {type:"mc",q:"Complete: 'Los colegas de ___ aprendí mucho son geniales.'",opts:["quien","quienes","que","los que"],ans:"quienes",hint:"After 'de' referring to multiple people, you need the plural form."},
        {type:"fb",opts:["quien","que","quienes","cual"],hint:"After 'para' referring to one female person, which word fits?",s:"La doctora para {1} trabajo es muy profesional.",a:"quien"},
        {type:"mc",q:"Which sentence is INCORRECT?",opts:["La chica que vive aquí es simpática.","La chica con quien salgo es simpática.","La chica con que salgo es simpática.","Los amigos de quienes hablo son divertidos."],ans:"La chica con que salgo es simpática.",hint:"One sentence has a preposition followed by the wrong pronoun for a person."},
        {type:"match",pairs:[{trg:"con quien",src:"with whom"},{trg:"a quien",src:"to whom"},{trg:"de quienes",src:"about whom (plural)"},{trg:"para quien",src:"for whom"}]},
        {type:"drag_fill",hint:"Fill the preposition, what I do with them, and a description (plural agreement).",s:"Las personas {1} quienes {2} son muy {3}.",blanks:{"1":"con","2":"trabajo","3":"amables"},pool:["con","trabajo","amables","de","trabajé","amable"]},
        {type:"mc",q:"'El amigo en quien confío me ayudó' means:",opts:["The friend where I trust helped me.","The friend who trusts me helped me.","The friend that I met helped me.","The friend in whom I trust helped me."],ans:"The friend in whom I trust helped me.",hint:"'En quien confío' uses the preposition 'en' plus the people-only pronoun."},
        {type:"fb",opts:["quien","que","quienes","donde"],hint:"After the preposition 'a' referring to one person, which pronoun?",s:"¿Conoces a la persona a {1} llamé ayer?",a:"quien"},
        {type:"mc",q:"Which is correct for 'the students for whom I prepared the exam'?",opts:["los estudiantes para quienes preparé el examen","los estudiantes para quien preparé el examen","los estudiantes que preparé el examen","los estudiantes para que preparé el examen"],ans:"los estudiantes para quienes preparé el examen",hint:"Multiple students after a preposition need the plural people pronoun."},
        {type:"drag_fill",hint:"Preposition + whom + past tense verb + family relation.",s:"El hombre {1} quien {2} es el {3} de mi amiga.",blanks:{"1":"a","2":"conocí","3":"hermano"},pool:["a","conocí","hermano","con","conozco","padre"]},
        {type:"mc",q:"Complete: '___ llegue primero puede elegir.'",opts:["Que","Quien","Cual","Donde"],ans:"Quien",hint:"At the start of a sentence meaning 'whoever' or 'he who', use the people pronoun."},
        {type:"fb",opts:["quienes","quien","que","cual"],hint:"After 'de' referring to multiple people, use the plural form for people.",s:"Los vecinos de {1} nos quejamos se mudaron.",a:"quienes"}
  ]},
  {id:"esp19l3",title:"Donde: Lugares y Recuerdos",icon:"📍",xp:20,board:true,steps:[
        {type:"intro",title:"Donde: Lugares y Recuerdos",desc:"Donde is the relative pronoun for places. It replaces 'en el/la que' and simplifies location-based relative clauses.",goals:["Use donde to describe places","Combine donde with different tenses","Distinguish donde from en el/la que"]},
        {type:"teach",trg:"la ciudad donde nací",src:"the city where I was born",pos:"noun",gender:"f",phonetic:"la see-oo-DAD DON-deh na-SEE",note:"Donde replaces a place noun in the second clause.\nLa ciudad + nací en la ciudad = la ciudad donde nací.",example:"A: ¿Cuál es la ciudad donde naciste?\nB: Nací en Sevilla, la ciudad donde crecí también.\nA: ¡Qué bonita! Es el lugar donde fui de vacaciones.\nB: Sí, es una ciudad donde siempre hace buen tiempo.",exampleSrc:"A: What's the city where you were born?\nB: I was born in Seville, the city where I also grew up.\nA: How beautiful! It's the place where I went on vacation.\nB: Yes, it's a city where the weather is always nice.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el lugar donde trabajamos",src:"the place where we work",pos:"noun",gender:"m",phonetic:"el loo-GAR DON-deh tra-ba-HA-mos",note:"Donde works with present, past, and future.\nEl lugar donde trabajo/trabajé/trabajaré.",example:"A: ¿Te gusta el lugar donde trabajamos?\nB: Sí, pero el edificio donde está la oficina es viejo.\nA: Es verdad. El barrio donde se encuentra es muy tranquilo.\nB: Al menos la cafetería donde almorzamos es buena.",exampleSrc:"A: Do you like the place where we work?\nB: Yes, but the building where the office is located is old.\nA: That's true. The neighborhood where it's located is very quiet.\nB: At least the cafeteria where we have lunch is good.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el barrio",src:"the neighborhood",pos:"noun",gender:"m",phonetic:"el BAR-ree-oh",note:"el barrio: masculine noun.\nCommon with donde in everyday descriptions.",example:"A: ¿En qué barrio vives?\nB: Vivo en el barrio donde está el mercado grande.\nA: Ah, el barrio donde abrieron el restaurante nuevo.\nB: Exacto. Es un barrio donde hay mucha vida.",exampleSrc:"A: What neighborhood do you live in?\nB: I live in the neighborhood where the big market is.\nA: Ah, the neighborhood where they opened the new restaurant.\nB: Exactly. It's a neighborhood where there's a lot of life.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"tip",title:"Donde = En El/La Que",text:"Donde is a shortcut for en + el/la/los/las + que:\n\nLa casa donde vivo = La casa en la que vivo\nEl parque donde jugamos = El parque en el que jugamos\n\nBoth are correct. Donde is more natural in speech.\nEn el/la que is more formal or written.\n\nWith other prepositions, add them before donde:\n  La casa hacia donde caminamos\n  El pueblo desde donde vine"},
        {type:"mc",q:"How do you say 'the school where I studied'?",opts:["la escuela donde estudié","la escuela que estudié","la escuela quien estudié","la escuela cual estudié"],ans:"la escuela donde estudié",hint:"For places, there's a dedicated relative pronoun meaning 'where'."},
        {type:"fb",opts:["donde","que","quien","cual"],hint:"Which pronoun is specifically for places?",s:"El hotel {1} nos quedamos era muy cómodo.",a:"donde"},
        {type:"mc",q:"Which sentence is correct?",opts:["La playa quien fuimos está en el sur.","La playa donde fuimos está en el sur.","La playa que fuimos está en el sur.","La playa lo que fuimos está en el sur."],ans:"La playa donde fuimos está en el sur.",hint:"The beach is a place. Use the place-specific pronoun."},
        {type:"fb",opts:["donde","que","quien","lo que"],hint:"The park is a place where you used to play. Which word fits?",s:"Este es el parque {1} jugábamos de niños.",a:"donde"},
        {type:"match",pairs:[
          {trg:"la ciudad donde nací",src:"the city where I was born"},
          {trg:"el café donde nos vemos",src:"the café where we meet"},
          {trg:"la oficina donde trabajo",src:"the office where I work"},
          {trg:"el país donde viví",src:"the country where I lived"}
        ]},
        {type:"mc",q:"'Donde' is equivalent to which longer form?",opts:["de el/la que","con el/la que","en el/la que","por el/la que"],ans:"en el/la que",hint:"Donde replaces the preposition of location plus the universal pronoun."},
        {type:"drag_fill",hint:"Place pronoun + article for clothing + the neighborhood.",s:"La tienda {1} compramos {2} ropa está en el {3} donde vivo.",blanks:{"1":"donde","2":"la","3":"barrio"},pool:["donde","la","barrio","que","el","ciudad"]},
        {type:"fb",opts:["donde","que","quien","lo que"],hint:"The restaurant is a place. Which pronoun goes with places?",s:"¿Recuerdas el restaurante {1} cenamos el viernes?",a:"donde"},
        {type:"mc",q:"Which is MORE formal: 'la casa donde vivo' or 'la casa en la que vivo'?",opts:["Neither is correct","la casa donde vivo","Both are equally formal","la casa en la que vivo"],ans:"la casa en la que vivo",hint:"The longer form with preposition + article + ___ sounds more written and polished."},
        {type:"drag_fill",hint:"Both are places. Use the place pronoun twice, then describe the contrast.",s:"El pueblo {1} crecí y la ciudad {2} ahora vivo son muy {3}.",blanks:{"1":"donde","2":"donde","3":"diferentes"},pool:["donde","donde","diferentes","que","quien","iguales"]},
        {type:"mc",q:"Complete: 'El país ___ viajamos tenía playas hermosas.'",opts:["donde","que","quien","lo que"],ans:"donde",hint:"A country is a place. Which dedicated pronoun describes location?"},
        {type:"fb",opts:["donde","que","quien","cual"],hint:"The university is a place where you studied.",s:"La universidad {1} estudié estaba en Barcelona.",a:"donde"},
        {type:"mc",q:"Complete: 'La habitación ___ dormimos tenía vistas al mar.'",opts:["que","donde","quien","lo que"],ans:"donde",hint:"A room is a place. Which pronoun is specifically for locations?"}
  ]},
  {id:"esp19l4",title:"Lo Que: Lo Abstracto",icon:"💭",xp:20,board:true,steps:[
        {type:"intro",title:"Lo Que: Lo Abstracto",desc:"Lo que means 'what' or 'the thing that'. It refers to abstract ideas, whole situations, or unknown things. It's one of the most useful constructions in Spanish.",goals:["Use lo que to express abstract ideas","Build lo que sentences with different tenses","Combine lo que with verbs of emotion and opinion"]},
        {type:"teach",trg:"lo que quiero es paz",src:"what I want is peace",pos:"intj",gender:null,phonetic:"lo keh kee-EH-ro es pas",note:"Lo que = what / the thing that.\nIt introduces an abstract or unknown idea.\nAlways two words: lo + que.",example:"A: ¿Qué necesitas ahora mismo?\nB: Lo que quiero es paz y tranquilidad.\nA: Entiendo. Lo que todos necesitamos es descansar.\nB: Exacto. Lo que importa es cuidarse a uno mismo.",exampleSrc:"A: What do you need right now?\nB: What I want is peace and quiet.\nA: I understand. What we all need is to rest.\nB: Exactly. What matters is taking care of yourself.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"no entiendo lo que dices",src:"I don't understand what you're saying",pos:"verb",gender:null,phonetic:"no en-tee-EN-do lo keh DEE-ses",note:"Lo que often follows verbs of perception:\nentender, saber, ver, oír, creer.",example:"A: Necesitamos cambiar lo que hacemos.\nB: No entiendo lo que dices. ¿Qué quieres cambiar?\nA: Lo que digo es que lo que tenemos no funciona.\nB: Ahora sí entiendo lo que propones.",exampleSrc:"A: We need to change what we do.\nB: I don't understand what you're saying. What do you want to change?\nA: What I'm saying is that what we have doesn't work.\nB: Now I understand what you're proposing.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"lo que más me gusta",src:"what I like the most",pos:"verb",gender:null,phonetic:"lo keh mas meh GOOS-ta",note:"Lo que más/menos + verb = what most/least.\nVery common in opinions and preferences.",example:"A: ¿Lo que más te gusta de tu trabajo?\nB: Lo que más me gusta es el horario flexible.\nA: Para mí, lo que más valoro es el equipo.\nB: Lo que menos me gusta son las reuniones largas.",exampleSrc:"A: What do you like most about your job?\nB: What I like the most is the flexible schedule.\nA: For me, what I value most is the team.\nB: What I like least are the long meetings.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"importar",src:"to matter / to be important",pos:"verb",gender:null,phonetic:"im-por-TAR",note:"Importar works like gustar: lo que importa.\nThe subject comes after the verb.",example:"A: Lo que importa es ser feliz.\nB: Sí, lo que no importa es el dinero.\nA: Bueno, lo que importa es tener suficiente.\nB: Tienes razón. Lo que de verdad importa es la salud.",exampleSrc:"A: What matters is being happy.\nB: Yes, what doesn't matter is money.\nA: Well, what matters is having enough.\nB: You're right. What truly matters is health.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"tip",title:"Lo Que vs Que",text:"Don't confuse them:\n\nQue = that/which/who (replaces a specific noun)\n  El libro que leí = The book that I read\n\nLo que = what / the thing that (no specific noun)\n  Lo que leí fue interesante = What I read was interesting\n\nUse lo que when:\n1. There's no specific noun to refer back to\n2. You mean 'what' (not 'that')\n3. You're talking about an abstract idea or situation"},
        {type:"mc",q:"How do you say 'what you need is patience'?",opts:["Lo que necesitas es paciencia.","Que necesitas es paciencia.","El que necesitas es paciencia.","La que necesitas es paciencia."],ans:"Lo que necesitas es paciencia.",hint:"For abstract 'what' with no specific noun, use the two-word neutral form."},
        {type:"fb",opts:["Lo","El","La","Que"],hint:"Before que, you need the neuter article for abstract ideas.",s:"{1} que me dijiste me sorprendió.",a:"Lo"},
        {type:"mc",q:"Which sentence uses lo que correctly?",opts:["No sé que lo pasó anoche.","No sé lo que pasó anoche.","No sé el que pasó anoche.","No sé la que pasó anoche."],ans:"No sé lo que pasó anoche.",hint:"'I don't know what happened' uses the abstract 'what' construction."},
        {type:"fb",opts:["gusta","gusto","gustan","gustas"],hint:"'Lo que' is a singular subject. Which conjugation matches a singular thing with 'me'?",s:"Lo que más me {1} es viajar.",a:"gusta"},
        {type:"match",pairs:[{trg:"lo que quiero",src:"what I want"},{trg:"lo que dices",src:"what you say"},{trg:"lo que pasó",src:"what happened"},{trg:"lo que importa",src:"what matters"}]},
        {type:"mc",q:"Complete: '___ más me molesta es el ruido.'",opts:["Que","El que","Lo que","Quien"],ans:"Lo que",hint:"'What bothers me most' is an abstract idea. Use the neuter form."},
        {type:"drag_fill",hint:"Two abstract 'what' constructions: what we can do + what we have.",s:"No entiendo {1} que {2} hacer con {3} que tenemos.",blanks:{"1":"lo","2":"podemos","3":"lo"},pool:["lo","podemos","lo","el","que","la"]},
        {type:"fb",opts:["que","cual","quien","donde"],hint:"After 'lo', which word completes 'what we did'?",s:"Lo {1} hicimos ayer fue muy divertido.",a:"que"},
        {type:"mc",q:"'Dime lo que piensas' means:",opts:["Tell me where you think.","Tell me that you think.","Tell me who thinks.","Tell me what you think."],ans:"Tell me what you think.",hint:"Dime is an imperative form of decir. Lo que signals an abstract idea, not a specific noun."},
        {type:"drag_fill",hint:"Two lo que constructions: what matters to me + that you be happy.",s:"{1} que {2} importa es {3} que seas feliz.",blanks:{"1":"Lo","2":"me","3":"lo"},pool:["Lo","me","lo","El","te","que"]},
        {type:"mc",q:"Which is correct?",opts:["Lo que necesitamos es más tiempo.","Lo que necesitamos son más tiempo.","El que necesitamos es más tiempo.","Lo quien necesitamos es más tiempo."],ans:"Lo que necesitamos es más tiempo.",hint:"Lo ___ as subject takes singular 'es' when followed by a singular noun."},
        {type:"fb",opts:["dijiste","dices","digas","dirás"],hint:"'What you said yesterday' needs a past tense verb for a completed action.",s:"Lo que {1} ayer me hizo pensar mucho.",a:"dijiste"}
  ]},
  {id:"esp19l5",title:"El Que, La Que, Los Que...",icon:"☝️",xp:20,board:true,steps:[
        {type:"intro",title:"El Que, La Que, Los Que...",desc:"El/la/los/las que means 'the one(s) that/who'. Unlike lo que (abstract), these forms refer to specific people or things and change for gender and number.",goals:["Use el/la/los/las que to specify people and things","Choose the correct gender and number","Combine with subjunctive for 'whoever' meaning"]},
        {type:"teach",trg:"el que llegue primero",src:"the one who arrives first / whoever arrives first",pos:"noun",gender:"m",phonetic:"el keh YEH-geh pree-MEH-ro",note:"El que + subjunctive = whoever.\nChanges form: el que (masc.), la que (fem.),\nlos que (masc. pl.), las que (fem. pl.).",example:"A: ¿Quién elige el restaurante?\nB: El que llegue primero puede elegir.\nA: Entonces la que llegue última paga la cuenta.\nB: Los que lleguen tarde se pierden el postre.",exampleSrc:"A: Who chooses the restaurant?\nB: The one who arrives first can choose.\nA: Then the one (female) who arrives last pays the bill.\nB: Those who arrive late miss dessert.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"las que son más caras",src:"the ones that are more expensive (feminine)",pos:"noun",gender:"pl",phonetic:"las keh son mas KA-ras",note:"Las que = the ones that (feminine plural).\nMatches gender/number of the noun it replaces.",example:"A: ¿Qué flores prefieres?\nB: Las que son más caras son las más bonitas.\nA: Pero las que están aquí también son lindas.\nB: Es verdad. Las que tienen color rosa me gustan más.",exampleSrc:"A: Which flowers do you prefer?\nB: The ones that are more expensive are the prettiest.\nA: But the ones that are here are also pretty.\nB: That's true. The ones that are pink I like more.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"los que quieran venir",src:"those who want to come",pos:"noun",gender:"pl",phonetic:"los keh kee-EH-ran beh-NEER",note:"Los/las que + subjunctive = those who / whoever.\nVery common in everyday instructions.",example:"A: ¿Quién viene a la excursión?\nB: Los que quieran venir pueden apuntarse.\nA: ¿Y las que no pueden ir el sábado?\nB: Las que prefieran pueden venir el domingo.",exampleSrc:"A: Who's coming on the trip?\nB: Those who want to come can sign up.\nA: And the ones (female) who can't go on Saturday?\nB: The ones who prefer can come on Sunday.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"El Que vs Lo Que: The Key Difference",text:"Lo que = 'what' (abstract, neuter, no specific noun)\n  Lo que quiero es paz. (What I want is peace.)\n\nEl/la/los/las que = 'the one(s) that' (specific, gendered)\n  El que quiera puede venir. (The one who wants can come.)\n  La que está rota es mía. (The one that's broken is mine.)\n\nTrick: if you can say 'the one' in English, use el/la que.\nIf you can say 'what' or 'the thing that', use lo que."},
        {type:"mc",q:"How do you say 'the ones (masc.) that are here'?",opts:["los que están aquí","las que están aquí","lo que están aquí","el que están aquí"],ans:"los que están aquí",hint:"Masculine plural 'ones' needs the masculine plural article before ___."},
        {type:"fb",opts:["El","La","Lo","Los"],hint:"'Whoever wants to' (masculine singular). Which article?",s:"{1} que quiera puede participar.",a:"El"},
        {type:"mc",q:"'Las que compraste son bonitas' refers to:",opts:["an abstract idea","specific feminine plural things","a male person","a place"],ans:"specific feminine plural things",hint:"Las que uses the ___ ___ article, pointing to ___ ___."},
        {type:"fb",opts:["Los","Las","Lo","El"],hint:"'Those who know Spanish' (mixed or masculine plural group). Which article?",s:"{1} que saben español pueden traducir.",a:"Los"},
        {type:"match",pairs:[
          {trg:"el que llegue primero",src:"the one (m.) who arrives first"},
          {trg:"la que tenga más puntos",src:"the one (f.) who has more points"},
          {trg:"los que quieran",src:"those (m.) who want to"},
          {trg:"las que están aquí",src:"the ones (f.) that are here"}
        ]},
        {type:"mc",q:"Complete: '___ que necesitas está en la mesa.'",opts:["La","El","Lo","Los"],ans:"Lo",hint:"'What you need' is abstract (no specific noun mentioned). Use the neuter."},
        {type:"drag_fill",hint:"Masculine plural articles + 'broken' + same article again for the second group.",s:"{1} que están {2} son de María y {3} que son nuevos son míos.",blanks:{"1":"Los","2":"rotos","3":"los"},pool:["Los","rotos","los","Las","rotas","el"]},
        {type:"fb",opts:["lleva","llevan","llevamos","llevo"],hint:"Singular feminine 'the one who wears'. Third person singular verb.",s:"La que {1} rojo es mi hermana.",a:"lleva"},
        {type:"mc",q:"Which uses the subjunctive correctly?",opts:["El que queriendo puede hablar.","El que quiere puede hablar.","El que querrá puede hablar.","El que quiera puede hablar."],ans:"El que quiera puede hablar.",hint:"'Whoever wants to' uses subjunctive because the person is unknown/hypothetical."},
        {type:"drag_fill",hint:"Plural article + subjunctive (unknown group) + infinitive after 'pueden'.",s:"{1} que {2} más lejos pueden {3} el autobús.",blanks:{"1":"Los","2":"vivan","3":"tomar"},pool:["Los","vivan","tomar","Las","viven","tomando"]},
        {type:"mc",q:"'La que me dijo la verdad fue Ana' means:",opts:["The one who told me the truth was Ana.","What told me the truth was Ana.","Where she told me the truth was Ana.","The place that told me the truth was Ana."],ans:"The one who told me the truth was Ana.",hint:"La que refers to a specific feminine person: 'the one who'."},
        {type:"fb",opts:["Los","Las","Lo","El"],hint:"'Those who don't have a ticket' (mixed group). Masculine plural article.",s:"{1} que no tengan entrada no pueden pasar.",a:"Los"},
        {type:"mc",q:"Complete: '___ que está en la mesa es para ti.'",opts:["Lo","La","El","Las"],ans:"La",hint:"If a specific feminine object is on the table, use the feminine article before que."}
  ]},
  {id:"esp19l6",title:"El Cual y Cuyo: Estilo Formal",icon:"🎩",xp:20,board:true,steps:[
        {type:"intro",title:"El Cual y Cuyo: Estilo Formal",desc:"El/la cual and cuyo/a are formal relative pronouns. El cual replaces que/quien in formal writing. Cuyo means 'whose' and agrees with the possessed noun.",goals:["Use el/la cual in formal contexts","Use cuyo/a/os/as to express possession","Recognize formal register in written Spanish"]},
        {type:"teach",trg:"el edificio en el cual trabajo",src:"the building in which I work",pos:"noun",gender:"m",phonetic:"el eh-dee-FEE-see-oh en el kwal tra-BA-ho",note:"El cual = which (formal). Changes form:\nel cual, la cual, los cuales, las cuales.\nUsed after prepositions in formal writing.",example:"A: ¿Ves el edificio en el cual trabajo?\nB: Sí, el edificio junto al cual hay un parque.\nA: Es la empresa para la cual he trabajado diez años.\nB: El proyecto en el cual participas suena interesante.",exampleSrc:"A: Do you see the building in which I work?\nB: Yes, the building next to which there is a park.\nA: It's the company for which I've worked ten years.\nB: The project in which you participate sounds interesting.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el hombre cuya casa",src:"the man whose house",pos:"noun",gender:"m",phonetic:"el OM-breh KOO-ya KA-sa",note:"Cuyo agrees with the POSSESSED thing, not the owner.\nel hombre cuya casa (casa is fem.)\nel hombre cuyo perro (perro is masc.)",example:"A: ¿Conoces al hombre cuya casa tiene jardín?\nB: Sí, el señor cuyo perro siempre ladra.\nA: Su esposa, cuyas flores son preciosas, es muy amable.\nB: Son los vecinos cuyos hijos van al mismo colegio.",exampleSrc:"A: Do you know the man whose house has a garden?\nB: Yes, the man whose dog always barks.\nA: His wife, whose flowers are beautiful, is very kind.\nB: They're the neighbors whose children go to the same school.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"cuyo / cuya / cuyos / cuyas",src:"whose (m.sg / f.sg / m.pl / f.pl)",pos:"noun",gender:null,phonetic:"KOO-yo / KOO-ya / KOO-yos / KOO-yas",note:"Four forms based on the possessed noun:\ncuyo libro (m.sg), cuya casa (f.sg),\ncuyos hijos (m.pl), cuyas flores (f.pl).",example:"A: La autora cuyo libro leímos dará una charla.\nB: ¿La escritora cuyas novelas son tan famosas?\nA: Sí, la persona cuyos libros están en todas las bibliotecas.\nB: Es la mujer cuya carrera admiro mucho.",exampleSrc:"A: The author whose book we read will give a talk.\nB: The writer whose novels are so famous?\nA: Yes, the person whose books are in every library.\nB: She's the woman whose career I admire a lot.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Cuyo: Agreement with the Possessed Noun",text:"Cuyo is unique: it agrees with what is OWNED, not the owner.\n\nEl hombre cuya casa = whose house (casa=fem.)\nEl hombre cuyo coche = whose car (coche=masc.)\nLa mujer cuyos hijos = whose children (hijos=masc.pl.)\nLa mujer cuyas amigas = whose friends (amigas=fem.pl.)\n\nThink: 'whose ___?' The blank determines the form.\nCuyo is mainly formal/literary. In speech, people avoid it."},
        {type:"mc",q:"Which is the formal equivalent of 'la casa donde vivo'?",opts:["la casa en la cual vivo","la casa en el cual vivo","la casa cuya vivo","la casa quien vivo"],ans:"la casa en la cual vivo",hint:"Match the article in 'el/la ___' to the gender of '___' (feminine)."},
        {type:"fb",opts:["la","el","lo","las"],hint:"'Empresa' is feminine singular. The article in this formal relative pronoun must match the noun's gender.",s:"La empresa para {1} cual trabajamos es internacional.",a:"la"},
        {type:"mc",q:"'El profesor cuyo examen es difícil' means:",opts:["The professor which exam is difficult","The professor whose exam is difficult","The professor that exam is difficult","The professor where exam is difficult"],ans:"The professor whose exam is difficult",hint:"Cuyo is the possessive relative pronoun. It agrees with the possessed noun, not the possessor."},
        {type:"fb",opts:["cuyas","cuyo","cuyos","cuya"],hint:"'Obras' is feminine plural. Cuyo must agree with the possessed noun.",s:"La artista {1} obras están en el museo es famosa.",a:"cuyas"},
        {type:"mc",q:"Which form of cuyo is correct? 'El país ___ capital es Madrid.'",opts:["cuyos","cuyo","cuya","cuyas"],ans:"cuya",hint:"'Capital' is feminine (la capital). Cuyo agrees with the possessed noun."},
        {type:"match",pairs:[{trg:"el cual",src:"which (m.sg, formal)"},{trg:"cuyo",src:"whose (m.sg)"},{trg:"las cuales",src:"which (f.pl, formal)"},{trg:"cuyas",src:"whose (f.pl)"}]},
        {type:"drag_fill",hint:"Novel is feminine (agree cuyo). Prize needs masculine article. Ceremony is feminine (la cual).",s:"El autor {1} novela ganó {2} premio fue invitado a la ceremonia en {3} cual participamos.",blanks:{"1":"cuya","2":"el","3":"la"},pool:["cuya","el","la","cuyo","los","el"]},
        {type:"fb",opts:["cuyas","cuyos","cuya","cuyo"],hint:"'Notas' (grades) is feminine plural. What form of cuyo matches?",s:"Los estudiantes {1} notas son las mejores recibirán un premio.",a:"cuyas"},
        {type:"mc",q:"In formal writing, which is preferred?",opts:["el informe sobre lo que discutimos","el informe sobre que discutimos","el informe sobre quien discutimos","el informe sobre el cual discutimos"],ans:"el informe sobre el cual discutimos",hint:"After a preposition in formal writing, use the formal form that agrees with the noun."},
        {type:"drag_fill",hint:"City is feminine (la cual), first person plural verb, then whose + historia (feminine).",s:"La ciudad en {1} cual {2} tiene monumentos {3} historia es fascinante.",blanks:{"1":"la","2":"vivimos","3":"cuya"},pool:["la","vivimos","cuya","el","viven","cuyo"]},
        {type:"mc",q:"Which sentence is grammatically correct?",opts:["El doctor cuyos pacientes están contentos es bueno.","El doctor cuyo pacientes están contentos es bueno.","El doctor cuya pacientes están contentos es bueno.","El doctor cuyos paciente están contentos es bueno."],ans:"El doctor cuyos pacientes están contentos es bueno.",hint:"'___' is masculine plural. Cuyo must agree: ___."},
        {type:"fb",opts:["la","el","lo","las"],hint:"'Universidad' is feminine singular. Choose the article form that agrees with the gender of the noun being referred to.",s:"La universidad en {1} cual estudié tiene buena reputación.",a:"la"},
        {type:"mc",q:"Complete: 'La mujer ___ hijo ganó el premio está orgullosa.'",opts:["cuya","cuyo","cuyos","cuyas"],ans:"cuyo",hint:"'Hijo' is masculine singular. The 'whose' pronoun agrees with the possessed noun."}
  ]},
  {id:"esp19l7",title:"Frases Complejas",icon:"🧩",xp:20,board:true,steps:[
        {type:"intro",title:"Frases Complejas",desc:"Now we combine relative pronouns with subjunctive, past tenses, and conditionals to build sophisticated sentences. This is where B1 grammar really comes together.",goals:["Combine relative pronouns with subjunctive mood","Layer relative clauses with past tenses","Build conditional sentences with relative pronouns"]},
        {type:"teach",trg:"busco a alguien que hable español",src:"I'm looking for someone who speaks Spanish",pos:"intj",gender:null,phonetic:"BOOS-ko a AL-gee-en keh AH-bleh es-pa-NYOL",note:"que + subjunctive = unknown/hypothetical person.\nque + indicative = known/specific person.\nBusco alguien que hable (unknown) vs Conozco alguien que habla (known).",example:"A: Busco a alguien que hable español y francés.\nB: Yo conozco a alguien que habla los dos idiomas.\nA: ¿La persona con quien trabajas, que vivió en París?\nB: Sí, ella es la que puede ayudarte con lo que necesitas.",exampleSrc:"A: I'm looking for someone who speaks Spanish and French.\nB: I know someone who speaks both languages.\nA: The person with whom you work, who lived in Paris?\nB: Yes, she's the one who can help you with what you need.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"lo que habría hecho",src:"what I would have done",pos:"intj",gender:null,phonetic:"lo keh ah-BREE-ah EH-cho",note:"Lo que combines with any tense:\nlo que hice (past), lo que haría (conditional),\nlo que habría hecho (conditional perfect).",example:"A: ¿Sabes lo que habría hecho en tu situación?\nB: No, pero lo que hice fue lo que me pareció correcto.\nA: Lo que haría ahora es diferente de lo que hice antes.\nB: Lo que importa es que aprendimos de lo que pasó.",exampleSrc:"A: Do you know what I would have done in your situation?\nB: No, but what I did was what seemed right to me.\nA: What I would do now is different from what I did before.\nB: What matters is that we learned from what happened.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"la razón por la que",src:"the reason why / the reason for which",pos:"noun",gender:"f",phonetic:"la ra-SON por la keh",note:"Por la que / por la cual = for which / why.\nVery common in explanations and arguments.",example:"A: ¿Cuál es la razón por la que te mudaste?\nB: La razón por la que vine fue el trabajo.\nA: Es la misma razón por la cual muchos se mudan aquí.\nB: Las razones por las que la gente viene son variadas.",exampleSrc:"A: What's the reason why you moved?\nB: The reason why I came was the job.\nA: It's the same reason for which many people move here.\nB: The reasons why people come are varied.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"tip",title:"Relative Pronoun + Tense Combos",text:"Relative pronouns work with ALL tenses. Key combos:\n\n1. que + subjunctive (hypothetical):\n  Busco algo que sea barato. (I'm looking for something cheap.)\n\n2. que + past tense (narrative):\n  El libro que leí ayer era bueno. (The book I read yesterday was good.)\n\n3. lo que + conditional (speculation):\n  Lo que haría es llamar. (What I would do is call.)\n\n4. donde + imperfect (habitual past):\n  El parque donde jugábamos ya no existe. (The park where we used to play no longer exists.)"},
        {type:"mc",q:"'Busco un hotel que tenga piscina.' Why subjunctive?",opts:["The hotel is unknown/hypothetical.","The hotel is in the past.","The hotel is formal.","The hotel is a place."],ans:"The hotel is unknown/hypothetical.",hint:"When looking for something you haven't found yet, the relative clause uses the uncertain mood."},
        {type:"fb",opts:["sepa","sabe","sabía","sabrá"],hint:"The person is unknown/not yet found. Use the mood for uncertainty.",s:"Necesito a alguien que {1} cocinar bien.",a:"sepa"},
        {type:"mc",q:"Which correctly combines lo que with the conditional?",opts:["Lo que hacería es hablar con ella.","Lo que haría es hablar con ella.","Lo que hago es hablar con ella.","Lo que haré es hablar con ella."],ans:"Lo que haría es hablar con ella.",hint:"The conditional of 'hacer' is '___'. Lo ___ + conditional = what I would do."},
        {type:"drag_fill",hint:"Preposition + people pronoun, feminine article + que, and indicative (known person).",s:"La persona con {1} hablé ayer es {2} que {3} ayudarme.",blanks:{"1":"quien","2":"la","3":"puede"},pool:["quien","la","puede","que","el","pueda"]},
        {type:"fb",opts:["sepa","sabe","sabía","sabrá"],hint:"After 'no hay nadie que', the uncertain mood is required.",s:"No hay nadie que {1} la respuesta.",a:"sepa"},
        {type:"mc",q:"Complete: 'El lugar donde ___ de niño ya no existe.'",opts:["jugaría","juegue","jugaba","jugué"],ans:"jugaba",hint:"Habitual past action. Which past tense describes what you 'used to do'?"},
        {type:"match",pairs:[
          {trg:"lo que haría",src:"what I would do"},
          {trg:"alguien que sepa",src:"someone who knows (hypothetical)"},
          {trg:"la razón por la que",src:"the reason why"},
          {trg:"donde vivíamos",src:"where we used to live"}
        ]},
        {type:"drag_fill",hint:"Abstract 'what' + imperfect gustar + place pronoun.",s:"Lo {1} más me {2} del lugar {3} crecí es la gente.",blanks:{"1":"que","2":"gustaba","3":"donde"},pool:["que","gustaba","donde","cual","gusta","que"]},
        {type:"mc",q:"Which is correct? 'I know a restaurant that has good paella.'",opts:["Busco un restaurante que tiene buena paella.","Conozco un restaurante que tenga buena paella.","Busco un restaurante que tiene buena paella.","Conozco un restaurante que tiene buena paella."],ans:"Conozco un restaurante que tiene buena paella.",hint:"You KNOW this restaurant (it exists, it's specific). Use indicative, not subjunctive."},
        {type:"fb",opts:["la","el","lo","las"],hint:"'Razón' is feminine. The article must match.",s:"La razón por {1} que no vine fue la lluvia.",a:"la"},
        {type:"drag_fill",hint:"People after preposition (plural) + place pronoun + masculine plural 'the ones'.",s:"Los amigos con {1} viajé al país {2} nací son {3} que más quiero.",blanks:{"1":"quienes","2":"donde","3":"los"},pool:["quienes","donde","los","quien","que","las"]},
        {type:"mc",q:"'Quiero algo que sea diferente de lo que tengo' combines:",opts:["subjunctive + lo que","indicative + lo que","conditional + donde","subjunctive + cuyo"],ans:"subjunctive + lo que",hint:"'Sea' is ___ (unknown thing) and 'lo ___ tengo' is the abstract 'what I have'."},
        {type:"fb",opts:["jugábamos","juguemos","jugamos","jugaremos"],hint:"Habitual past action ('we used to play'). Which past tense describes repeated actions?",s:"El parque donde {1} de niños ya no existe.",a:"jugábamos"}
  ]},
  {id:"esp19l8",title:"Repaso: Todos los Relativos",icon:"🏆",xp:20,board:true,steps:[
        {type:"intro",title:"Repaso: Todos los Relativos",desc:"Time to bring together all the relative pronouns: que, quien/quienes, donde, lo que, el/la/los/las que, el/la cual, and cuyo/a. Let's see how well you can choose the right one.",goals:["Choose correctly between all relative pronouns","Combine relative pronouns in complex sentences","Demonstrate mastery of formal vs informal register"]},
        {type:"tip",title:"The Complete Relative Pronoun Map",text:"Quick reference:\n\nque: universal (people + things, no preposition)\nquien/quienes: people only (after prepositions)\ndonde: places only\nlo que: abstract ideas ('what')\nel/la/los/las que: 'the one(s) that'\nel/la cual: formal 'which' (after prepositions)\ncuyo/a/os/as: 'whose' (agrees with possessed noun)\n\nDefault to que when in doubt. It covers 80% of cases."},
        {type:"mc",q:"Complete: 'El chico ___ conocí ayer es muy simpático.'",opts:["que","quien","donde","lo que"],ans:"que",hint:"No preposition before the pronoun. The universal connector works for people here."},
        {type:"fb",opts:["donde","que","quien","lo que"],hint:"A city is a place. Which pronoun is dedicated to locations?",s:"La ciudad {1} nací está en el sur de España.",a:"donde"},
        {type:"mc",q:"Complete: 'No entiendo ___ estás diciendo.'",opts:["que","lo que","el que","donde"],ans:"lo que",hint:"'What you're saying' is abstract. Use the neuter form."},
        {type:"fb",opts:["quien","que","donde","la que"],hint:"After the preposition 'con' referring to a person, which pronoun?",s:"La profesora con {1} hablé me ayudó mucho.",a:"quien"},
        {type:"mc",q:"Complete: '___ quiera participar debe inscribirse.'",opts:["Lo que","Que","Quien","Donde"],ans:"Quien",hint:"'Whoever wants to participate' starts with the people pronoun."},
        {type:"drag_fill",hint:"Place pronoun + person after preposition + abstract 'what I miss most'.",s:"El país {1} viví y la persona con {2} compartí piso son {3} que más extraño.",blanks:{"1":"donde","2":"quien","3":"lo"},pool:["donde","quien","lo","que","quienes","los"]},
        {type:"match",pairs:[
          {trg:"la chica que vino",src:"the girl who came"},
          {trg:"con quien hablé",src:"with whom I spoke"},
          {trg:"lo que pasó",src:"what happened"},
          {trg:"el lugar donde vivo",src:"the place where I live"},
          {trg:"cuya casa es grande",src:"whose house is big"}
        ]},
        {type:"mc",q:"Which is the FORMAL version of 'la empresa donde trabajo'?",opts:["la empresa cuya trabajo","la empresa que trabajo","la empresa quien trabajo","la empresa en la cual trabajo"],ans:"la empresa en la cual trabajo",hint:"The formal register uses a preposition + gendered article + ___."},
        {type:"fb",opts:["cuyos","cuyo","cuya","cuyas"],hint:"'Libros' is masculine plural. The 'whose' pronoun must agree.",s:"El escritor {1} libros son famosos vive en esta calle.",a:"cuyos"},
        {type:"mc",q:"Complete: '___ están cansados pueden irse.'",opts:["Los que","Lo que","Quien","Donde"],ans:"Los que",hint:"'Those who are tired' (masculine plural). Which gendered form of 'the ones that'?"},
        {type:"drag_fill",hint:"Abstract 'what' + gustar (singular) + person after preposition.",s:"{1} que me {2} de la persona con {3} trabajo es su honestidad.",blanks:{"1":"Lo","2":"gusta","3":"quien"},pool:["Lo","gusta","quien","El","gustan","que"]},
        {type:"fb",opts:["tenga","tiene","tenía","tendrá"],hint:"The restaurant is hypothetical (not found yet). Use the uncertain mood.",s:"Busco un restaurante que {1} buena comida mexicana.",a:"tenga"},
        {type:"mc",q:"Which sentence combines the most relative pronouns correctly?",opts:["La persona que quien hablé me recomendó el lugar que venden que necesito.","La persona con quien hablé me recomendó el lugar donde venden lo que necesito.","La persona donde hablé me recomendó el lugar quien venden lo donde necesito.","La persona lo que hablé me recomendó el lugar cuyo venden que necesito."],ans:"La persona con quien hablé me recomendó el lugar donde venden lo que necesito.",hint:"Person after preposition + place + abstract 'what'. Each pronoun has its own job."},
        {type:"drag_fill",hint:"Feminine article (razón) + universal connector + abstract 'what'.",s:"La razón por {1} que elegí el trabajo {2} tengo es {3} que me apasiona.",blanks:{"1":"la","2":"que","3":"lo"},pool:["la","que","lo","el","donde","la"]},
        {type:"mc",q:"Final challenge: 'El hombre cuya esposa trabaja donde yo estudié es con quien hablé.' How many relative pronouns?",opts:["Four: cuya, donde, quien, que","Two: cuya, donde","Three: cuya, donde, quien","One: cuya"],ans:"Three: cuya, donde, quien",hint:"Count each relative word: possession + place + person after preposition."},
        {type:"fb",opts:["que","cual","quien","donde"],hint:"After 'lo', complete the abstract 'what we learned' construction.",s:"Lo {1} aprendimos hoy nos ayudará en todo lo que hagamos.",a:"que"}
  ]}
]};
